mapper.select:
SELECT r.*, u.nickname, u.phone, s.storeName as store_name, s2.storeName as device_store_name FROM user_open_door_record as r LEFT JOIN user_info as u on u.userId = r.user_id LEFT JOIN store as s on s.storeId = r.store_id LEFT JOIN store as s2 on s2.storeId = r.device_store_id
r.status = 1
and u.phone LIKE concat('%',#{phone},'%')
and s.storeName LIKE concat('%',#{store_name},'%')
and s2.storeName LIKE concat('%',#{device_store_name},'%')
and r.store_id = #{store_id}
AND r.store_id in (${storeIds})
AND r.create_time between #{startTime} and #{endTime}
ORDER BY r.id desc
limit #{offset}, #{limit}
